import{_ as t,o,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"52. Right To Disconnect","description":"","frontmatter":{"title":"52. Right To Disconnect","eba":"Nurses and Midwives 2024-2028","topics":["leave","right-to-disconnect"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/52-right-to-disconnect.md","filePath":"ebas/nurses-midwives/hours-of-work/52-right-to-disconnect.md"}'),n={name:"ebas/nurses-midwives/hours-of-work/52-right-to-disconnect.md"};function a(i,e,l,c,p,h){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_52-right-to-disconnect" tabindex="-1">52. Right To Disconnect <a class="header-anchor" href="#_52-right-to-disconnect" aria-label="Permalink to &quot;52. Right To Disconnect&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p>This clause applies from 8 July 2024.</p><p><strong>52.1</strong> General</p><p>The Right to Disconnect refers to an Employee’s right under the Act to be able to disengage from work and refrain from engaging in work-related communications, such as emails, telephone calls or other messages, while an Employee is off-duty, including during periods of approved leave or rostered days off.</p><p>The primary challenge to an Employee’s Right to Disconnect is out of hours contact to determine availability for additional shifts.</p><p><strong>52.2</strong> Filling vacancies through the Supplementary Roster</p><p>This Agreement makes provision for:</p><p><strong>(a)</strong> Availability arrangements via the supplementary rosters,</p><p><strong>(b)</strong> Change of roster allowance, and</p><p><strong>(c)</strong> On-call and recall arrangements.</p><p>The Employer will consult the Supplementary Roster before reliance on mechanisms described at subclauses (b) or (c) above, or otherwise contacting an Employee (including through text message or instant messaging applications (e.g. WhatsApp) to determine their availability for an additional shift or different shift.</p><p><strong>52.3</strong> Employer Obligations to Support Right to Disconnect</p><p>To support the Right of Employees to Disconnect, the Employer will:</p><p><strong>(a)</strong> Undertake a review of its arrangements for contacting Employees out of hours to determine availability, to ensure the system for contact is as efficient as possible, avoiding unnecessary contacts (such as multiple incidents of contact for the same shift) and prioritising use of the supplementary roster; and</p><p><strong>(b)</strong> Report the results of the review under subclause 52.3(a) to the WIC and the status of supplementary roster arrangements.</p><p><strong>(c)</strong> The actions made under subclauses 52.3(a) and (b) shall occur within the first six months of this Agreement commencing operation and shall be reported to the WIC.</p><p><strong>(d)</strong> The WIC will work cooperatively to address any identified instances of contact inconsistent with the clause during the life of this Agreement.</p><p><strong>52.4</strong> Employee Right to Disconnect in relation to requests for additional or changed hours of work</p><p>Employees are not required to read or respond to emails, messages or phone calls outside of their on-duty periods with respect to offers or requests for additional or changed hours of work unless:</p><p><strong>(a)</strong> the Employee has indicated availability for the relevant shift in accordance with <a href="/eba/ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.html">clause 46</a> (Supplementary Roster and Additional Shifts);</p><p><strong>(b)</strong> the Employee is in receipt of the on-call allowance for that period as set out in <a href="/eba/ebas/nurses-midwives/allowances/33-allowances-related-to-overtime.html">clause 33.2</a>; or</p><p><strong>(c)</strong> the Employee has been directed by the Employer to perform overtime.</p><p>Plain language terms: after hours contact, out of hours, work-life boundary, no phone calls after work.</p>',24)])])}const u=t(n,[["render",a]]);export{g as __pageData,u as default};
